INSERT INTO `comentarios` (`id`, `padre`, `nombre`, `email`, `fecha`, `titulo`, `comentario`, `aceptado`) VALUES (1,1,'Angel BarbÃ³ BenedÃ­','anlulin@hotmail.com','1528131022','Plaza de las Monjas nÂº 5 Entresuelo A','Hola.\nNo me deja firmar el formulario, me dice que hay errores y estÃ¡ todo bien.\n\nGracias\n\nAngel',0),
(2,2,'Elena','helenamarkina@hotmail.com','1528217132','Firma','Quiero el tren d cercanÃ­as hasta Gallur',1),
